from typing import List, Optional
from collections import deque

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def build_tree(nodes: List[Optional[int]]) -> Optional[TreeNode]:
    if not nodes or nodes[0] is None:
        return None
    root = TreeNode(nodes[0])
    queue = deque([root])
    i = 1
    while queue and i < len(nodes):
        node = queue.popleft()
        if i < len(nodes) and nodes[i] is not None:
            node.left = TreeNode(nodes[i])
            queue.append(node.left)
        i += 1
        if i < len(nodes) and nodes[i] is not None:
            node.right = TreeNode(nodes[i])
            queue.append(node.right)
        i += 1
    return root

def max_path_sum(root: List[Optional[int]]) -> int:
    root = build_tree(root)

    def max_down(node):
        """Max gain going down from this node (must go straight down)."""
        if not node:
            return 0
        return max(0, node.val + max(max_down(node.left), max_down(node.right)))

    def max_through(node):
        """Max path sum for any path in the subtree rooted at node."""
        if not node:
            return float('-inf')
        left_gain = max(0, max_down(node.left))
        right_gain = max(0, max_down(node.right))
        through_here = node.val + left_gain + right_gain
        return max(through_here, max_through(node.left), max_through(node.right))

    return max_through(root)

class TreeNode {
  constructor(val = 0, left = null, right = null) { this.val = val; this.left = left; this.right = right; }
}
function buildTree(nodes) {
  if (!nodes || nodes.length === 0 || nodes[0] === null) return null;
  const root = new TreeNode(nodes[0]); const queue = [root]; let i = 1;
  while (queue.length > 0 && i < nodes.length) {
    const node = queue.shift();
    if (i < nodes.length && nodes[i] !== null) { node.left = new TreeNode(nodes[i]); queue.push(node.left); } i++;
    if (i < nodes.length && nodes[i] !== null) { node.right = new TreeNode(nodes[i]); queue.push(node.right); } i++;
  }
  return root;
}
function maxPathSum(root) {
  root = buildTree(root);
  let res = root.val;
  function dfs(node) {
    if (!node) return 0;
    const leftGain = Math.max(dfs(node.left), 0);
    const rightGain = Math.max(dfs(node.right), 0);
    res = Math.max(res, node.val + leftGain + rightGain);
    return node.val + Math.max(leftGain, rightGain);
  }
  dfs(root);
  return res;
}
